css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #030712; color: white; min-height: 100vh; display: flex; align-items: center; justify-content: center; }
.container { display: grid; grid-template-columns: 1fr 1fr; min-height: 100vh; width: 100%; }
.left { background: linear-gradient(135deg, #4c1d95, #be185d, #9f1239); padding: 80px 60px; display: flex; flex-direction: column; justify-content: center; }
.brand { font-size: 28px; font-weight: 900; margin-bottom: 60px; }
.left h1 { font-size: 64px; font-weight: 900; line-height: 1; margin-bottom: 20px; }
.left p { font-size: 17px; color: rgba(255,255,255,0.7); line-height: 1.7; margin-bottom: 48px; max-width: 340px; }
.left-stats { display: flex; gap: 32px; } .l-stat strong { display: block; font-size: 32px; font-weight: 900; } .l-stat span { color: rgba(255,255,255,0.6); font-size: 13px; }
.right { background: #0a0a0f; display: flex; align-items: center; justify-content: center; padding: 40px; }
.form-card { width: 100%; max-width: 420px; }
.form-card h2 { font-size: 36px; font-weight: 800; margin-bottom: 8px; }
.form-sub { color: #6b7280; font-size: 14px; margin-bottom: 28px; } .form-sub a { color: #ec4899; text-decoration: none; font-weight: 600; }
.social-login { display: flex; flex-direction: column; gap: 12px; margin-bottom: 24px; }
.social-btn { height: 48px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.12); background: rgba(255,255,255,0.04); color: white; font-size: 15px; font-weight: 600; cursor: pointer; transition: background 0.2s; } .social-btn:hover { background: rgba(255,255,255,0.08); }
.divider { display: flex; align-items: center; gap: 16px; margin-bottom: 24px; color: #374151; font-size: 13px; } .divider::before, .divider::after { content: ''; flex: 1; height: 1px; background: rgba(255,255,255,0.08); }
.form-group { margin-bottom: 18px; }
.form-group label { display: flex; justify-content: space-between; font-size: 14px; font-weight: 600; margin-bottom: 8px; color: #e2e8f0; }
.forgot { color: #ec4899; text-decoration: none; font-weight: 500; }
.form-group input { width: 100%; height: 50px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.05); color: white; padding: 0 16px; font-size: 15px; outline: none; transition: border-color 0.2s; } .form-group input:focus { border-color: #ec4899; }
.password-wrap { position: relative; }
.password-wrap input { padding-right: 48px; }
.toggle-pw { position: absolute; right: 14px; top: 50%; transform: translateY(-50%); background: none; border: none; cursor: pointer; font-size: 16px; }
.remember { display: flex; align-items: center; gap: 10px; margin-bottom: 24px; } .remember label { font-size: 14px; color: #9ca3af; cursor: pointer; }
.login-btn { width: 100%; height: 52px; border-radius: 14px; border: none; background: linear-gradient(135deg, #ec4899, #be185d); color: white; font-size: 16px; font-weight: 800; cursor: pointer; transition: opacity 0.2s; } .login-btn:hover { opacity: 0.9; }
.error-msg { color: #ef4444; font-size: 13px; text-align: center; margin-top: 12px; min-height: 20px; }

js:
function togglePw() { const pw = document.getElementById('password'); pw.type = pw.type === 'password' ? 'text' : 'password'; }
function login() {
  const email = document.getElementById('email').value;
  const password = document.getElementById('password').value;
  const err = document.getElementById('error-msg');
  if (!email || !password) { err.textContent = '⚠️ Lütfen tüm alanları doldurun.'; return; }
  if (!email.includes('@')) { err.textContent = '⚠️ Geçerli bir e-posta girin.'; return; }
  if (password.length < 6) { err.textContent = '⚠️ Şifre en az 6 karakter olmalı.'; return; }
  err.style.color = '#22c55e';
  err.textContent = '✓ Giriş başarılı! Yönlendiriliyorsunuz...';
  document.querySelector('.login-btn').textContent = '✓ Başarılı';
  document.querySelector('.login-btn').style.background = '#22c55e';
}
